// معالج الأخطاء العام لضمان إرجاع استجابة JSON دائماً في حال حدوث أي خطأ غير متوقع
app.use((err: any, req: express.Request, res: express.Response, next: express.NextFunction) => {
  console.error('[GLOBAL ERROR HANDLER] Caught error:', err);
  res.status(err.status || 500).json({
    success: false,
    error: err.message || 'حدث خطأ غير متوقع في الخادم',
    details: err.stack || null
  });
});

// تهيئة Vite كوسيط في التطوير، وتقديم الملفات الثابتة في الإنتاج
async function startServer() {
  // فحص وإصلاح قاعدة البيانات فوراً عند إقلاع السيرفر وتصحيح الكتب القديمة في الخلفية لتجنب عرقلة بدء تشغيل السيرفر
  repairDatabase().catch(err => console.error("[DB REPAIR] Failed during start:", err));

  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
